def simulate(days, seed):
    random.seed(seed)
    cash=cash0
    cohorts=[c.copy() for c in small]
    ents=[e.copy() for e in ent]
    ent_events=initial_ent_events(days)
    active0=sum(c['n'] for c in cohorts if c['group']=='S2')
    market_cap=max(145000,random.gauss(164000,23000))
    cap_growth=max(0.00008,random.gauss(0.00040,0.00014))
    paid_lpd=max(0.007,min(0.022,random.lognormvariate(math.log(0.013),0.30)))
    net_rate=max(0.00055,min(0.00145,random.gauss(0.00100,0.00022)))
    conv_base=max(0.48,min(0.72,random.gauss(0.595,0.050)))
    mixA=max(0.18,min(0.36,random.gauss(0.265,0.035)))
    mixB=max(0.58,min(0.80,random.gauss(0.725,0.040)))
    if mixA+mixB>0.995: mixB=0.995-mixA
    macro_bad=max(0, random.gauss(0.055,0.035))
    support_repair=random.uniform(0.0,0.035)
    for d in range(DAY+1, DAY+days+1):
        rel=d-DAY
        active_s2=sum(c['n'] for c in cohorts if c['group']=='S2')
        cap=market_cap*((1+cap_growth)**rel)
        denom=max(0.05,1-active0/market_cap)
        rel_sat=max(0.02,min(1.25,(1-active_s2/cap)/denom))
        ad_s2=20000.0
        if active_s2>0.94*cap: ad_s2=15000.0
        if active_s2>0.975*cap: ad_s2=8000.0
        paid=max(0,random.gauss(ad_s2*paid_lpd*rel_sat, max(20,ad_s2*paid_lpd*0.35)))
        net=max(0,random.gauss(active_s2*net_rate*rel_sat, max(15,active_s2*net_rate*0.35)))
        leads=paid+net
        cv=conv_base + support_repair*min(1,rel/21)
        for bd,b in boosts:
            if d>=bd: cv+=min(0.045,b*0.10)
        cv-=macro_bad*min(1,rel/35)
        if random.random()<0.018: cv-=random.uniform(0.04,0.14)
        cv=max(0.56,min(0.90,random.gauss(cv,0.035)))
        new=leads*cv
        ma=max(0.30,min(0.58,random.gauss(mixA,0.04)))
        mb=max(0.38,min(0.68,random.gauss(mixB,0.04)))
